const body = $json.body;
const locale = body.locale || 'ka';
const name = body.name || 'User';
const email = body.email;

const content = {
  ka: {
    subject: 'კეთილი იყოს თქვენი მობრძანება BrandFlow-ში',
    greet: 'გამარჯობა',
    p1: 'BrandFlow-ით თქვენი სოციალური მედია კონტენტი ავტომატურად შეიქმნება.',
    p2: 'დაიწყეთ პირველი პოსტის შექმნა და დანარჩენს ჩვენ გავაკეთებთ.',
    cta: 'დაიწყე ახლა',
    reminder: 'თქვენ ჯერ პირველი პოსტი არ შეგიქმნიათ. დაიწყეთ ახლა!'
  },
  ru: {
    subject: 'Добро пожаловать в BrandFlow',
    greet: 'Привет',
    p1: 'С BrandFlow ваш контент для социальных сетей создается автоматически.',
    p2: 'Создайте свой первый пост, а остальное мы возьмём на себя.',
    cta: 'Начать сейчас',
    reminder: 'Вы ещё не создали свой первый пост. Начните сейчас!'
  },
  en: {
    subject: 'Welcome to BrandFlow',
    greet: 'Hello',
    p1: 'With BrandFlow, your social media content is created automatically.',
    p2: 'Create your first post and we will handle the rest.',
    cta: 'Get Started',
    reminder: 'You haven\'t created your first post yet. Get started now!'
  }
};

const t = content[locale] || content.en;

const htmlBody = `
<h1>${t.greet}, ${name}!</h1>
<p>${t.p1}</p>
<p>${t.p2}</p>
<a href="https://brandflow.ge/${locale}/dashboard" style="
  display: inline-block;
  background: #6366F1;
  color: white;
  padding: 12px 24px;
  border-radius: 8px;
  text-decoration: none;
  font-weight: bold;
">${t.cta}</a>
<p style="margin-top: 20px; color: #666; font-size: 12px;">
BrandFlow — Take the photo. We handle the rest.
</p>
`;

return [{
  json: {
    email,
    name,
    subject: t.subject,
    htmlBody,
    reminderSubject: t.reminder,
    locale,
    userId: body.userId
  }
}];
